insert into public.survey_responses (
  question_id,
  answer_id,
  outlet_id,
  created_by,
  other_text,
  response_date,
  created_at
)
select
  question_id,
  answer_id,
  outlet_id,
  created_by,
  other_text,
  response_date,
  created_at
from legacy_rows lr
where not exists (
  select 1
  from public.survey_responses sr
  where sr.question_id = lr.question_id
    and sr.outlet_id = lr.outlet_id
    and sr.answer_id is not distinct from lr.answer_id
    and sr.created_at = lr.created_at
);

